/**
 * 架构设计阶段：
 * 基于需求文档，设计技术架构、模块划分、接口定义
 * - DesignAgent: AI 交互执行
 * - DesignPhase: Workflow 调度入口
 */

import type { PhaseId } from "../models.js";
import { SpecWorkflowAgent } from "./base_agent.js";
import { BasePhase } from "./base_phase.js";

export class DesignAgent extends SpecWorkflowAgent {
  readonly phaseId: PhaseId = "design";
  readonly promptTemplate = "spec_design";
  readonly phaseName = "架构设计";

  protected getArtifactFileName(): string {
    return "design.md";
  }
}

export class DesignPhase extends BasePhase {
  readonly phaseId: PhaseId = "design";
  readonly phaseName = "架构设计";

  protected override createAgent(): SpecWorkflowAgent {
    return new DesignAgent();
  }
}
